import{_ as e,c as r,o as t,R as a}from"./chunks/framework.CIzs38F0.js";const S=JSON.parse('{"title":"1.ZFS简介","description":"","frontmatter":{},"headers":[],"relativePath":"guide/Linux/Storage/zfs/index.md","filePath":"guide/Linux/Storage/zfs/index.md","lastUpdated":1712053412000}'),i={name:"guide/Linux/Storage/zfs/index.md"},o=a('<ul><li><p>文档</p><p><a href="https://docs.oracle.com/cd/E26926_01/html/E25826/gavwg.html#scrolltoc" target="_blank" rel="noreferrer">https://docs.oracle.com/cd/E26926_01/html/E25826/gavwg.html#scrolltoc</a></p><p><a href="https://openzfs.org/wiki/Main_Page" target="_blank" rel="noreferrer">https://openzfs.org/wiki/Main_Page</a></p></li></ul><h1 id="_1-zfs简介" tabindex="-1">1.ZFS简介 <a class="header-anchor" href="#_1-zfs简介" aria-label="Permalink to &quot;1.ZFS简介&quot;">​</a></h1><p>2001年Matthew Ahrens 和 Jeff Bonwick开发出了ZFS)最初作为Sun Microsystem公司的Solaris核心文件系统，焕发出了强大的生命力：</p><ul><li>2008年，ZFS被移植到FreeBSD</li><li>同年， <a href="https://zfsonlinux.org/" target="_blank" rel="noreferrer">ZFS on Linux</a> 项目将ZFS引入Linux</li><li>2013年， <a href="http://www.open-zfs.org/wiki/Main_Page" target="_blank" rel="noreferrer">OpenZFS项目</a> 创建，维护和管理了核心ZFS代码，被广泛用于Unix-like系统中 (从2010年8月的OpenSolaris中Fork出代码)</li></ul><p>ZFS集成了逻辑卷管理的文件系统，具有高扩展性，并且提供了大量保护措施防止数据损坏，并且支持大存储容量、提供高性能数据压缩、卷管理也提供了快照以及写时复制、连续性完整性检查和自动修复，以及高级的RAID-Z(类似RAID5/6)，并且提供原生NFSv4 ACL等功能</p><h2 id="_1-1zfs特性" tabindex="-1">1.1ZFS特性 <a class="header-anchor" href="#_1-1zfs特性" aria-label="Permalink to &quot;1.1ZFS特性&quot;">​</a></h2><p><a href="https://openzfs.org/wiki/Features" target="_blank" rel="noreferrer">https://openzfs.org/wiki/Features</a></p><p>ZFS是 128 位文件系统，这个设计如此超前，以至于理论极限可能在当前现实中永远无法遇到 (OMG，我只能赞叹) – 项目领导Bonwick曾说：”要填满一个128位的文件系统，将耗尽地球上所有存储设备。除非你拥有煮沸整个海洋的能量，不然你不可能将其填满。”</p><p>特性:</p><ul><li>防止数据损坏，支持数据和元数据的完整性检查。</li><li>持续的完整性验证和自动修复</li><li>数据冗余与镜像，RAID-Z1/2/3 [和 DRAID] 支持高存储容量——高达 256 万亿 yobibytes (2^128 字节，大到足以装下世界上所有数据) 使用 LZ4、GZIP 或 ZSTD 透明压缩节省空间</li><li>支持使用硬件加速的本机加密</li><li>具有 快照(snapshots) 和 写时复制(copy-on-write) 的高效存储</li><li>高效的本地或远程复制 — 使用 ZFS 发送和接收仅发送更改的块</li></ul>',10),l=[o];function n(s,p,_,c,h,f){return t(),r("div",null,l)}const u=e(i,[["render",n]]);export{S as __pageData,u as default};
